// 진짜 검증 영상 → MOCK_VIDEOS 형식 변환
window.VERIFIED_VIDEOS = RAW;
window.MOCK_VIDEOS = RAW.map(v => {
  let originalUrl, embedUrl, thumbnail;
  if (v.platform === "Shorts" && v.youtubeId) {
    originalUrl = `https://www.youtube.com/shorts/${v.youtubeId}`;
    embedUrl = `https://www.youtube.com/embed/${v.youtubeId}?rel=0&modestbranding=1`;
    thumbnail = `https://i.ytimg.com/vi/${v.youtubeId}/hqdefault.jpg`;
  } else if (v.platform === "TikTok" && v.tiktokId) {
    originalUrl = `https://www.tiktok.com/@${v.tiktokUser}/video/${v.tiktokId}`;
    embedUrl = `https://www.tiktok.com/embed/v2/${v.tiktokId}`;
    thumbnail = null;
  } else if (v.platform === "Reels" && v.instagramShortcode) {
    originalUrl = `https://www.instagram.com/reel/${v.instagramShortcode}/`;
    embedUrl = `https://www.instagram.com/reel/${v.instagramShortcode}/embed`;
    thumbnail = null;
  }
  return {
    ...v,
    originalUrl, embedUrl, thumbnail,
    signals: { paid: false, code: false, cta: true, affiliate: false },
    compliance: ["med","pet"].includes(v.industry) ? "pass" : null,
    revenueClass: v.verifiedMetric ? "verified" : "unknown",
    applyTip: v.applyTip || `${window.INDUSTRY_LABEL[v.industry] || v.industry} 카테고리 — 1인 디자이너가 ${v.country === "KR" ? "한국" : "미국"} ${window.INDUSTRY_LABEL[v.industry] || v.industry} 클라이언트 영상에 후킹·구조 이식 가능.`,
    estimatedCost: { d2c:"30~80만", beauty:"30~80만", med:"200~500만 (의료 심의)", pet:"45~110만", smb:"30~80만", edu:"40~100만", creator:"40~100만", fitness:"40~90만", food:"30~80만", kpop:"—", b2b:"40~100만" }[v.industry] || "30~80만",
  };
});
window.IS_VERIFIED_DATA = true;
window.IS_LIVE_DATA = false;

// localStorage 실데이터가 있으면 덮어쓰기
(function () {
  try {
    const live = JSON.parse(localStorage.getItem("hookpilot_live_videos") || "null");
    if (live && Array.isArray(live) && live.length > 0) {
      window.MOCK_VIDEOS = live;
      window.IS_LIVE_DATA = true;
      window.IS_VERIFIED_DATA = false;
    }
  } catch (e) {}
})();
